-- FSI_DEMO_DB.BANKING.CUSTOMERS

CREATE OR REPLACE TABLE FSI_DEMO_DB.BANKING.CUSTOMERS (

    CUSTOMER_ID VARCHAR(20) NOT NULL,
    FIRST_NAME VARCHAR(50),
    LAST_NAME VARCHAR(50),
    EMAIL VARCHAR(100),
    PHONE VARCHAR(20),
    DATE_OF_BIRTH DATE,
    SSN_LAST_4 VARCHAR(4),
    ADDRESS_LINE1 VARCHAR(200),
    CITY VARCHAR(100),
    STATE VARCHAR(2),
    ZIP_CODE VARCHAR(10),
    COUNTRY VARCHAR(50) DEFAULT 'USA',
    CUSTOMER_SINCE DATE,
    KYC_STATUS VARCHAR(20),
    KYC_VERIFIED_DATE DATE,
    RISK_SCORE NUMBER(3,0),
    SEGMENT VARCHAR(30),
    ANNUAL_INCOME NUMBER(15,2),
    EMPLOYMENT_STATUS VARCHAR(30),
    CHURN_RISK_FLAG BOOLEAN DEFAULT FALSE,
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    UPDATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (CUSTOMER_ID)

);





